import{_ as a,o,c as t,a2 as n}from"./chunks/framework.IwO0Hdn_.js";const u=JSON.parse('{"title":"[UI / PRESENTATION] F-02.4 — Filtro por Rango de Fechas","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-02.4_filtro_fechas.md","filePath":"backlog/F-02.4_filtro_fechas.md","lastUpdated":null}'),r={name:"backlog/F-02.4_filtro_fechas.md"};function i(s,e,c,d,l,p){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="ui-presentation-f-02-4-—-filtro-por-rango-de-fechas" tabindex="-1">[UI / PRESENTATION] F-02.4 — Filtro por Rango de Fechas <a class="header-anchor" href="#ui-presentation-f-02-4-—-filtro-por-rango-de-fechas" aria-label="Permalink to &quot;[UI / PRESENTATION] F-02.4 — Filtro por Rango de Fechas&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-02 — Listado y Filtrado de Logs Activos</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Frontend (Livewire/Blade)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-02.1_tabla_logs_paginada.html">F-02.1</a></td><td>Componente Livewire <code>LogsTable</code> base implementado</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero filtrar la tabla de logs por un rango de fechas con fecha inicio y fecha fin Para analizar incidencias ocurridas en un período de tiempo concreto</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Happy Path):</strong> Dado que introduzco una fecha inicio y una fecha fin válidas, cuando aplico el filtro, entonces la tabla muestra solo los logs cuyo <code>created_at</code> está dentro del rango (inclusive en ambos extremos).</li><li>[ ] <strong>Escenario 2 (Solo fecha inicio):</strong> Dado que introduzco solo fecha inicio, cuando aplico el filtro, entonces se muestran todos los logs desde esa fecha hasta hoy.</li><li>[ ] <strong>Escenario 3 (Rango inválido):</strong> Dado que la fecha fin es anterior a la fecha inicio, cuando intento aplicar el filtro, entonces se muestra un error de validación y no se lanza la petición.</li><li>[ ] <strong>Escenario 4 (Zona horaria):</strong> Dado que el servidor opera en UTC, cuando el usuario introduce una fecha, entonces el frontend normaliza a UTC antes de enviar al backend.</li><li>[ ] <strong>Requisito Técnico:</strong> Parámetros <code>date_from</code> y <code>date_to</code> en formato ISO 8601. Validación en Laravel FormRequest. Índice en columna <code>created_at</code> (NFR-LAT-02).</li></ul>',12)])])}const g=a(r,[["render",i]]);export{u as __pageData,g as default};
